decimal recQtySum = 0;
decimal doaSum = 0;
decimal recQtyRejSum = 0;
decimal rejectedQtySum = 0;
decimal recQtyPlukRejSum = 0;
decimal pluckRejectSum = 0;
decimal recQtyMedicalCondemnationSum  = 0;
decimal medicalCondemnationSum  = 0;
decimal recQtyAcceptWtSum = 0;
decimal acceptWtSum = 0;

private void xrTableCell24_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
    // --- Declare local variables for current record ---
decimal recQty = 0;
decimal doa = 0;

// --- Read values safely ---
if (GetCurrentColumnValue("RecQty") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("RecQty").ToString()))
{
    recQty = Convert.ToDecimal(GetCurrentColumnValue("RecQty"));
}

if (GetCurrentColumnValue("DOA") != null &&
    !string.IsNullOrEmpty(GetCurrentColumnValue("DOA").ToString()))
{
    doa = Convert.ToDecimal(GetCurrentColumnValue("DOA"));
}

// --- Accumulate totals across all records ---

recQtySum += recQty;
doaSum += doa;

// --- Equation (same as Iif(Sum([RecQty]) <> 0, Sum([DOA]) * 100 / Sum([RecQty]), 0)) ---
decimal result = 0;
if (recQtySum != 0)
    result = (doaSum * 100) / recQtySum;
else
    result = 0;

// --- Assign result to cell ---
XRTableCell cell = sender as XRTableCell;
cell.Text = result.ToString("N2"); // format with 2 decimal places
}

